<template>
  <div
    class="loading-container"
    :class="{ 'loading-hidden': !isLoading }"
    v-if="showLoader"
  >
    <div class="loading">
      <div class="loader"></div>
    </div>
  </div>
  <div v-if="!isLoading">
    <div class="No_Found" v-if="$route.name === 'Not_Found'">
      <router-view />
    </div>
    <App-layout v-else>
      <router-view />
      <QuickView />
      <v-snackbar
        v-model="bar"
        location="left bottom"
        max-width="300"
        timeout="3000"
      >
        {{ itemTitle }} Has Been added to your Cart Successfully!
        <template v-slot:actions>
          <v-icon @click="bar = false">mdi-close</v-icon>
        </template>
      </v-snackbar>
    </App-layout>
  </div>
</template>
<script setup>
import AppLayout from "@/components/global/AppLayout.vue";
import QuickView from "./components/global/QuickView.vue";
import { ref, inject, onMounted } from "vue";
import { RouterView } from "vue-router";
const emitter = inject("emitter");
const bar = ref(false);
const itemTitle = ref(null);
const isLoading = ref(true);
const showLoader = ref(true);
const removeLoaderFromDOM = () => {
  setTimeout(() => {
    showLoader.value = false;
  }, 500);
};
onMounted(() => {
  // First Thing Start Loading
  isLoading.value = true;
  showLoader.value = true;
  // After Content Ready Reset Loading:
  window.addEventListener("load", () => {
    isLoading.value = false;
    removeLoaderFromDOM();
  });
  // If Internet Too Fast, Close Loading
  if (document.readyState === "complete") {
    isLoading.value = false;
    removeLoaderFromDOM();
  }

  emitter.on("showMsg", (data) => {
    itemTitle.value = data;
    bar.value = true;
  });
});
</script>
<style>
/* Loading Container */
.loading-container {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100vh;
  z-index: 9999;
  pointer-events: none;
  transition: transform 0.5s ease-in-out;
}
/* Hide Loading */
.loading-hidden {
  transform: translateX(-100%);
}
/* Content Loading */
.loading {
  position: relative;
  width: 100%;
  height: 100%;
  background: #111;
  animation: colorRot 5000ms linear infinite;
}

.loading .loader {
  position: absolute;
  width: 100px;
  height: 100px;
  top: calc(50% - 50px);
  left: calc(50% - 50px);
  animation: rotAnim 750ms ease-in-out infinite;
  z-index: 9999;
}

.loading .loader::before,
.loading .loader::after {
  content: "";
  position: absolute;
  width: 25%;
  height: 25%;
  top: 0;
  left: 0;
  border-radius: 50%;
  background: #fff;
  box-shadow: 0 0 40px #7aa8ff, 0 0 10px #7aa8ff;
}

.loading .loader::after {
  top: unset;
  left: unset;
  bottom: 0;
  right: 0;
}

/* Animations */
@keyframes colorRot {
  0% {
    filter: hue-rotate(0deg);
  }
  100% {
    filter: hue-rotate(360deg);
  }
}

@keyframes rotAnim {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

#app {
  font-family: Avenir, Helvetica, Arial, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

nav {
  padding: 30px;
}

nav a {
  font-weight: bold;
  color: #2c3e50;
}

nav a.router-link-exact-active {
  color: #42b983;
}
.v-rating {
  display: flex;
  gap: 5px;
}
input[type="number"]::-webkit-outer-spin-button,
input[type="number"]::-webkit-inner-spin-button {
  appearance: none;
  -webkit-appearance: none;
  margin: 0;
}
</style>
