import { defineStore } from "pinia";
import axios from "axios";
export const productsModule = defineStore("prodcutsModule", {
  state: () => ({
    flashDeals: [],
    fragrancesProduct: [],
    market: [],
    beauty: [],
    furniture: [],
    categoryProducts: [],
    categories: [
      {
        title: "beauty",
        route: "beauty",
      },
      {
        title: "Laptops",
        route: "laptops",
      },
      {
        title: "Furniture",
        route: "furniture",
      },
      {
        title: "Groceries",
        route: "groceries",
      },
      {
        title: "Men's Watches",
        route: "mens-watches",
      },
      {
        title: "Women's Bags",
        route: "womens-bags",
      },
      {
        title: "Fragrances",
        route: "fragrances",
      },
    ],
    singalProduct: {},
  }),
  actions: {
    async getProducts() {
      await axios
        .get("https://dummyjson.com/products")
        .then((res) => {
          this.fragrancesProduct = res.data.products.filter(
            (el) => el.category === "fragrances"
          );
          this.flashDeals = res.data.products.slice(6, 14);
          this.market = res.data.products.filter(
            (el) => el.category === "groceries"
          );
          this.beauty = res.data.products.filter(
            (el) => el.category === "beauty"
          );
          this.furniture = res.data.products.filter(
            (el) => el.category === "furniture"
          );
        })
        .catch((err) => console.log(err));
    },
    async getProductsByCategory(cat) {
      await axios
        .get(`https://dummyjson.com/products/category/${cat}`)
        .then((res) => (this.categoryProducts = res.data));
    },
    async getSingleProduct(productId) {
      await axios
        .get(`https://dummyjson.com/products/${productId}`)
        .then((res) => {
          this.singalProduct = res.data;
        });
    },
  },
});
