<template>
  <div class="drawer">
    <v-navigation-drawer
      v-model="drawer"
      location="right"
      temporary
      :width="props.windowWidth <= 767 ? props.windowWidth / 2 : 370"
      class="pr-1 cart-drawer"
    >
      <v-card class="px-0 shop-empty" elevation="0">
        <v-card-title
          class="pl-0 pr-2 font-weight-bold d-flex justify-space-between align-center"
          style="font-size: 17px"
          >Shopping Cart
          <v-icon @click="drawer = false">mdi-close</v-icon></v-card-title
        >
        <v-card-text class="px-0 py-0" color="#6f6f6f" style="color: #6f6f6f"
          >{{ cartItems.length }} Items</v-card-text
        >
        <v-card-text
          class="px-0 py-0 my-2"
          style="color: #6f6f6f"
          v-if="!cartItems.length"
          >Free Shipping for all orders over $10000.00</v-card-text
        >
        <v-card-text
          class="px-0 py-0 text-center"
          style="color: #6f6f6f"
          v-if="!cartItems.length"
          >Your cart is Empty</v-card-text
        >
        <div
          class="bar-parent mt-4 position-relative mr-2"
          v-if="cartItems.length"
        >
          <svg-icon
            type="mdi"
            :path="icons.ship"
            width="30"
            height="30"
            :color="
              parseInt((calcTotalPrice / 10000) * 100) < 50
                ? '#f44336'
                : parseInt((calcTotalPrice / 10000) * 100) >= 50 &&
                  parseInt((calcTotalPrice / 10000) * 100) < 100
                ? '#ff9800'
                : '#4CAF50'
            "
            :style="`    position: absolute;
              bottom: 0%;
              z-index: 1;
              left: calc(${
                parseInt((calcTotalPrice / 10000) * 100) <= 100
                  ? parseInt((calcTotalPrice / 10000) * 100)
                  : 100
              }% - 30px);
              transition: 0.15s all ease-in-out;`"
          ></svg-icon>
          <v-progress-linear
            :color="
              parseInt((calcTotalPrice / 10000) * 100) < 50
                ? 'red'
                : parseInt((calcTotalPrice / 10000) * 100) >= 50 &&
                  parseInt((calcTotalPrice / 10000) * 100) < 100
                ? 'orange'
                : 'green'
            "
            height="10"
            :model-value="
              parseInt((calcTotalPrice / 10000) * 100) <= 100
                ? parseInt((calcTotalPrice / 10000) * 100)
                : 100
            "
            striped
          ></v-progress-linear>
        </div>
        <v-card-text
          class="px-0 pt-2"
          style="color: #6f6f6f"
          v-if="cartItems.length && 10000 - calcTotalPrice > 0"
          >Only ${{ 10000 - calcTotalPrice }} away from Free
          Shipping</v-card-text
        >
        <v-card-text
          class="px-0 pt-2"
          style="color: #6f6f6f"
          v-if="cartItems.length && 10000 - calcTotalPrice <= 0"
          >Your Order now is included Free Shipping</v-card-text
        >
        <v-card-actions v-if="!cartItems.length">
          <v-btn
            class="w-100"
            style="border-color: rgb(199, 199, 199)"
            variant="outlined"
            rounded="xl"
            density="compact"
            height="45"
            @click="drawer = false"
            >Continue Shopping</v-btn
          >
        </v-card-actions>
      </v-card>
      <!-- Shop not Empty DownBelow Cart: -->
      <v-card
        class="pa-0 items-card overflow-y-auto mt-5"
        elevation="0"
        v-if="cartItems.length"
        max-height="240"
      >
        <v-container class="px-1">
          <v-row
            v-for="item in cartItems"
            :key="item.id"
            class="align-center mb-4"
          >
            <v-col cols="12" sm="5">
              <img :src="item.thumbnail" :alt="item.thumbnail" class="w-100" />
            </v-col>
            <v-col cols="12" sm="7">
              <v-card elevation="0">
                <v-card-title class="text-wrap text-subtitle-2 pl-0"
                  >{{ item.title }} Sample - {{ item.category }}</v-card-title
                >
                <v-card-text class="px-0" style="color: #6f6f6f">
                  Category: {{ item.category }}
                </v-card-text>
                <v-card-text class="px-0 pb-0 pt-0 font-weight-bold">
                  ${{
                    Math.ceil(
                      item.price - item.price * (item.discountPercentage / 100)
                    ) * item.quantity
                  }}
                </v-card-text>
                <div
                  class="item-footer d-flex justify-space-between align-center"
                >
                  <div
                    class="counter px-1"
                    style="
                      border-radius: 30px;
                      border: 1px solid rgb(201, 201, 201);
                      width: fit-content;
                    "
                  >
                    <v-icon
                      size="19"
                      color="#606060"
                      @click="item.quantity > 1 ? item.quantity-- : false"
                      >mdi-minus</v-icon
                    >
                    <input
                      type="number"
                      style="
                        border: none;
                        outline: none;
                        text-align: center;
                        width: 35px;
                        font-size: 12px;
                        color: #606060;
                      "
                      class="py-3"
                      min="1"
                      v-model="item.quantity"
                    />
                    <v-icon size="19" color="#606060" @click="item.quantity++"
                      >mdi-plus</v-icon
                    >
                  </div>
                  <v-icon size="22" @click="cart.deleteItem(item.id)"
                    >mdi-close</v-icon
                  >
                </div>
              </v-card>
            </v-col>
          </v-row>
        </v-container>
      </v-card>
      <v-card class="px-0 mt-5" elevation="0" v-if="cartItems.length">
        <v-card-actions class="flex-column justify-center align-center ga-4">
          <v-btn
            variant="elevated"
            density="compact"
            height="45"
            elevation="0"
            class="w-100 text-capitalize"
            rounded="xl"
            style="border-color: rgb(199, 199, 199)"
            color="blue"
            @click="toCheckout"
            >check out</v-btn
          >
          <v-btn
            variant="outlined"
            density="compact"
            height="45"
            class="w-100 text-capitalize mx-0"
            rounded="xl"
            style="border-color: rgb(199, 199, 199)"
            @click="$router.push({ name: 'cart_page' })"
            >view cart</v-btn
          >
        </v-card-actions>
      </v-card>
    </v-navigation-drawer>
  </div>
</template>
<script setup>
import { ref, onMounted, inject, computed, defineProps } from "vue";
import { cartStore } from "@/stores/cart";
import { icons } from "@/icons/icons";
import { useRouter } from "vue-router";
// Variables DownBelow
const cart = cartStore();
const emitter = inject("emitter");
const drawer = ref(true);
const router = useRouter();
// Props
const props = defineProps({
  windowWidth: {
    type: Number,
    required: true,
  },
});
// Function Not Yet Created It,
// Testing DownBelow
// console.log();
// * Hooks DownBelow Functions
const cartItems = computed(() => cart.cartitems);
onMounted(() => {
  // When Navbar Sent Function Open Sidebar Listen init:
  emitter.on("openCart", () => {
    drawer.value = !drawer.value;
  });
  cart.getCartItems();
});

const calcTotalPrice = computed(() => {
  let total = 0;
  cart.cartitems.forEach((product) => {
    const discountPrice =
      product.price - product.price * (product.discountPercentage / 100);
    total += Math.ceil(discountPrice * product.quantity);
  });
  return total;
});
const toCheckout = () => {
  cart.setToLocalStorage();
  router.push({ name: "check_out" });
};
</script>

