<template>
  <div
    :class="`quick-view ${$route.name != 'check_out' ? 'mt-16' : 'mt-0'}`"
    :key="Product.id"
  >
    <v-dialog v-model="dialog" max-width="900" max-height="500">
      <v-icon
        class="position-absolute"
        style="
          right: -14px;
          top: -14px;
          background-color: black;
          font-size: 18px;
          padding: 13px;
          z-index: 10;
        "
        color="rgb(198,198,198)"
        @click="dialog = false"
        >mdi-close</v-icon
      >
      <v-card elevation="0" class="content-card">
        <v-container fluid class="bg-white pt-10 px-10">
          <v-row>
            <v-col cols="12" md="7">
              <img
                :src="tab ? tab : Product.thumbnail"
                alt=""
                class="w-100"
                height="400"
                v-if="!loading"
              />
              <v-skeleton-loader
                type="image,image , image"
                v-if="loading"
              ></v-skeleton-loader>
              <v-tabs center-active height="130" v-model="tab" class="mt-10">
                <v-tab
                  v-for="(img, i) in Product.images"
                  :key="i"
                  class="mx-10"
                  :value="img"
                >
                  <img :src="img" alt="" width="70" height="100" />
                </v-tab>
              </v-tabs>
            </v-col>
            <v-col cols="12" md="5" class="pt-0 pl-6 mt-8 mt-md-0">
              <v-skeleton-loader
                type="article,article , article"
                v-if="loading"
              ></v-skeleton-loader>
              <v-card elevation="0" v-if="!loading">
                <v-card-title class="px-0 text-h6 font-weight-bold text-wrap"
                  >{{ Product.title }} Sample - {{ Product.category }} For
                  Sale</v-card-title
                >
                <div class="rating-parent d-flex align-center ga-1">
                  <v-rating
                    v-model="Product.rating"
                    half-increments
                    readonly
                    color="yellow-darken-2"
                    size="x-small"
                    density="compact"
                  ></v-rating>
                  <v-chip variant="text" color="rgb(96,96,96)"
                    >Stock:{{ Product.stock }}</v-chip
                  >
                </div>
                <v-card-text
                  class="px-0"
                  style="color: #606060; font-size: 14px"
                  >{{ Product.description }}</v-card-text
                >
                <v-card-text
                  class="px-0 pt-0"
                  style="color: #606060; font-size: 14px"
                  >Brand:{{ Product.brand }}</v-card-text
                >
                <v-card-text
                  class="px-0 pt-0"
                  style="color: #606060; font-size: 14px"
                  >Availability:{{
                    Product.stock > 0 ? "In Stock" : "Out Of Stock"
                  }}</v-card-text
                >
                <v-card-text
                  class="px-0 pt-0"
                  style="color: #606060; font-size: 14px"
                >
                  <del>${{ Product.price }}</del> From
                  <v-chip variant="text" color="error" class="font-weight-bold">
                    ${{
                      Math.floor(
                        Product.price -
                          Product.price * (Product.discountPercentage / 100)
                      )
                    }}
                  </v-chip>
                </v-card-text>
                <v-card-text class="px-0 pt-0"> Quantity </v-card-text>
                <div
                  class="counter px-1"
                  style="
                    border-radius: 30px;
                    border: 1px solid rgb(201, 201, 201);
                    width: fit-content;
                  "
                >
                  <v-icon size="22" @click="quantity > 1 ? quantity-- : false"
                    >mdi-minus</v-icon
                  >
                  <input
                    type="number"
                    style="
                      border: none;
                      outline: none;
                      text-align: center;
                      width: 60px;
                      font-size: 13px;
                    "
                    class="py-3"
                    min="1"
                    v-model="quantity"
                  />
                  <v-icon size="22" @click="quantity++">mdi-plus</v-icon>
                </div>
                <v-card-text class="pl-0">
                  Subtotal: ${{
                    Math.floor(
                      Product.price -
                        Product.price * (Product.discountPercentage / 100)
                    ) * quantity
                  }}
                </v-card-text>
                <v-card-actions class="mt-2 w-100 px-0">
                  <v-btn
                    variant="outlined"
                    style="
                      text-transform: none;
                      background-color: rgb(34, 34, 34);
                    "
                    class="w-75"
                    density="compact"
                    height="50"
                    rounded="xl"
                    color="#fff"
                    @click="addToCart(Product)"
                    :loading="btnLoading"
                    >Add To Cart</v-btn
                  >
                </v-card-actions>
              </v-card>
            </v-col>
          </v-row>
        </v-container>
      </v-card>
    </v-dialog>
  </div>
</template>

<script setup>
// Import downBelow
import { ref, onMounted } from "vue";
import { VSkeletonLoader } from "vuetify/lib/components";
import { cartStore } from "@/stores/cart";
// * Variables DownBelow
const cart = cartStore();
const loading = ref(false);
const dialog = ref(false);
const tab = ref(null);
const quantity = ref(1);
const Product = ref({});
const btnLoading = ref(false);

// Config Inject
import { inject } from "vue";
const emitter = inject("emitter");

// functions Api DownBelow
onMounted(() => {
  emitter.on("OpenQuickView", (data) => {
    loading.value = true;
    Product.value = data;
    dialog.value = true;
    setTimeout(() => {
      loading.value = false;
    }, 100);
  });
});

const addToCart = (item) => {
  item.quantity = quantity.value;
  btnLoading.value = true;
  setTimeout(() => {
    btnLoading.value = false;
    cart.addItems(item);
    emitter.emit("openCart");
    emitter.emit("showMsg", item.title);
    dialog.value = false;
  }, 1000);
};
</script>

